// ── Volume formatting ──────────────────────────────────────────────────────────
function fmtVolLocal(kg) {
  if (!kg || kg === 0) return '—';
  if (kg >= 1000) return `${(kg / 1000).toFixed(1)}k kg`;
  return `${Math.round(kg)} kg`;
}

// ── BodyGraph ─────────────────────────────────────────────────────────────────
const DAY_ABBR = ['S', 'M', 'T', 'W', 'T', 'F', 'S'];

const MONTHS_FULL = ['January','February','March','April','May','June','July','August','September','October','November','December'];

const MUSCLE_LIST = [
  { label: 'Abdominals', key: 'abdominals' },
  { label: 'Abductors',  key: 'abductors' },
  { label: 'Adductors',  key: 'adductors' },
  { label: 'Biceps',     key: 'biceps' },
  { label: 'Calves',     key: 'calves' },
  { label: 'Chest',      key: 'chest' },
  { label: 'Forearms',   key: 'forearms' },
  { label: 'Glutes',     key: 'glutes' },
  { label: 'Hamstrings', key: 'hamstrings' },
  { label: 'Lats',       key: 'lats' },
  { label: 'Lower Back', key: 'lower back' },
  { label: 'Middle Back',key: 'middle back' },
  { label: 'Neck',       key: 'neck' },
  { label: 'Quadriceps', key: 'quadriceps' },
  { label: 'Shoulders',  key: 'shoulders' },
  { label: 'Traps',      key: 'traps' },
  { label: 'Triceps',    key: 'triceps' },
];

function weekStartFor(offset) {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const sun = new Date(today);
  sun.setDate(today.getDate() - today.getDay() + offset * 7);
  return sun;
}

function formatWeekRange(start, end) {
  const s = String(start.getDate()).padStart(2, '0');
  const e = String(end.getDate()).padStart(2, '0');
  if (start.getMonth() === end.getMonth()) {
    return `${s}-${e} ${MONTHS_FULL[start.getMonth()]} ${start.getFullYear()}`;
  }
  const sm = MONTHS_FULL[start.getMonth()].slice(0, 3);
  const em = MONTHS_FULL[end.getMonth()].slice(0, 3);
  return `${s} ${sm} – ${e} ${em} ${end.getFullYear()}`;
}

// ── BodyDistributionView ──────────────────────────────────────────────────────
function BodyDistributionView({ sessions, onClose }) {
  const [weekOffset, setWeekOffset] = useState(0);

  const weekStart = useMemo(() => weekStartFor(weekOffset), [weekOffset]);
  const weekEnd   = useMemo(() => { const d = new Date(weekStart); d.setDate(d.getDate() + 6); return d; }, [weekStart]);

  const days = useMemo(() => Array.from({ length: 7 }, (_, i) => {
    const d = new Date(weekStart); d.setDate(weekStart.getDate() + i); return d;
  }), [weekStart]);

  const weekSessions = useMemo(() => {
    const sk = weekStart.toLocaleDateString('en-CA');
    const ek = weekEnd.toLocaleDateString('en-CA');
    return sessions.filter(s => {
      const k = new Date(s.date).toLocaleDateString('en-CA');
      return k >= sk && k <= ek;
    });
  }, [sessions, weekStart, weekEnd]);

  const sessionDateKeys = useMemo(() => {
    const set = new Set();
    for (const s of weekSessions) set.add(new Date(s.date).toLocaleDateString('en-CA'));
    return set;
  }, [weekSessions]);

  const bodyPartCounts = useMemo(() => {
    const counts = {};
    for (const s of weekSessions) {
      for (const ex of s.exercises || []) {
        const bp = (ex.bodyPart || getExerciseByName(ex.name)?.bodyPart || '').toLowerCase();
        if (BP_MAP[bp]) {
          const n = (ex.sets || []).filter(set => set.completed).length;
          counts[bp] = (counts[bp] || 0) + n;
        }
      }
    }
    return counts;
  }, [weekSessions]);

  const intensities = useMemo(() => {
    const counts = {};
    for (const s of weekSessions) {
      for (const ex of s.exercises || []) {
        const bp = (ex.bodyPart || getExerciseByName(ex.name)?.bodyPart || '').toLowerCase();
        const slugs = BP_MAP[bp];
        if (slugs) {
          const n = (ex.sets || []).filter(set => set.completed).length;
          slugs.forEach(slug => { counts[slug] = (counts[slug] || 0) + n; });
        }
      }
    }
    const result = {};
    for (const [k, v] of Object.entries(counts)) result[k] = Math.min(v / 20, 1);
    return result;
  }, [weekSessions]);

  const totalSets = useMemo(() => Object.values(bodyPartCounts).reduce((a, b) => a + b, 0), [bodyPartCounts]);
  const todayKey  = new Date().toLocaleDateString('en-CA');

  return (
    <div style={{ position: 'fixed', inset: 0, zIndex: 150, background: 'var(--bg)', display: 'flex', flexDirection: 'column' }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', padding: '54px 16px 12px', borderBottom: '1px solid var(--border)', flexShrink: 0 }}>
        <button onClick={onClose} style={{ background: 'none', border: 'none', color: 'var(--text)', cursor: 'pointer', display: 'flex', alignItems: 'center', padding: '4px 8px 4px 0' }}>
          <ArrowLeft size={22} />
        </button>
        <span style={{ flex: 1, textAlign: 'center', fontSize: 17, fontWeight: 700, color: 'var(--text)' }}>Body distribution</span>
        <div style={{ width: 30 }} />
      </div>

      <div style={{ flex: 1, overflowY: 'auto', paddingBottom: 40 }}>
        {/* Week nav */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '14px 12px 10px' }}>
          <button onClick={() => setWeekOffset(o => o - 1)} style={{ background: 'none', border: 'none', color: 'var(--text)', cursor: 'pointer', padding: 6, display: 'flex' }}>
            <ChevronLeft size={20} />
          </button>
          <span style={{ fontSize: 15, fontWeight: 600, color: 'var(--text)' }}>{formatWeekRange(weekStart, weekEnd)}</span>
          <button onClick={() => setWeekOffset(o => o + 1)} disabled={weekOffset >= 0} style={{ background: 'none', border: 'none', color: weekOffset >= 0 ? 'var(--border)' : 'var(--text)', cursor: weekOffset >= 0 ? 'default' : 'pointer', padding: 6, display: 'flex' }}>
            <ChevronRight size={20} />
          </button>
        </div>

        {/* Day strip */}
        <div style={{ display: 'flex', gap: 4, padding: '0 16px 20px' }}>
          {days.map((d, i) => {
            const key = d.toLocaleDateString('en-CA');
            const hasWorkout = sessionDateKeys.has(key);
            const isToday = key === todayKey;
            return (
              <div key={i} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 4 }}>
                <span style={{ fontSize: 11, fontWeight: 600, color: 'var(--text3)' }}>{DAY_ABBR[d.getDay()]}</span>
                <div style={{
                  width: 30, height: 30, borderRadius: '50%',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  background: hasWorkout ? 'var(--accent)' : 'transparent',
                  border: isToday && !hasWorkout ? '1.5px solid var(--text3)' : 'none',
                }}>
                  <span style={{ fontSize: 13, fontWeight: hasWorkout ? 700 : 400, color: hasWorkout ? '#fff' : isToday ? 'var(--text)' : 'var(--text2)' }}>
                    {d.getDate()}
                  </span>
                </div>
              </div>
            );
          })}
        </div>

        {/* Body diagram */}
        <div style={{ padding: '0 16px 28px' }}>
          <MuscleDiagram intensities={intensities} size={150} />
        </div>

        {/* Muscle table */}
        <div style={{ borderTop: '1px solid var(--border)' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', padding: '10px 20px', borderBottom: '1px solid var(--border)' }}>
            <span style={{ fontSize: 12, fontWeight: 700, color: 'var(--text3)', textTransform: 'uppercase', letterSpacing: '0.6px' }}>Muscle</span>
            <span style={{ fontSize: 12, fontWeight: 700, color: 'var(--text3)', textTransform: 'uppercase', letterSpacing: '0.6px' }}>Sets</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', padding: '15px 20px', borderBottom: '1px solid var(--border)' }}>
            <span style={{ fontSize: 15, fontWeight: 600, color: 'var(--text)' }}>Total</span>
            <span style={{ fontSize: 15, fontWeight: 600, color: 'var(--text)' }}>{totalSets}</span>
          </div>
          {MUSCLE_LIST.map(({ label, key }) => {
            const count = bodyPartCounts[key] || 0;
            return (
              <div key={key} style={{ display: 'flex', justifyContent: 'space-between', padding: '15px 20px', borderBottom: '1px solid var(--border)' }}>
                <span style={{ fontSize: 15, color: 'var(--text)' }}>{label}</span>
                <span style={{ fontSize: 15, color: count > 0 ? 'var(--text)' : 'var(--text3)' }}>{count}</span>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

function BodyGraph({ sessions, onTap }) {
  const days = useMemo(() => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date(today);
      d.setDate(today.getDate() - (6 - i));
      return d;
    });
  }, []);

  const sessionDateKeys = useMemo(() => {
    const set = new Set();
    for (const s of sessions) set.add(new Date(s.date).toLocaleDateString('en-CA'));
    return set;
  }, [sessions]);

  // Build intensity map (0..1) per muscle slug from last 7 days
  const muscleIntensities = useMemo(() => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const cutoff = new Date(today);
    cutoff.setDate(today.getDate() - 6);

    const counts = {};
    for (const s of sessions) {
      if (new Date(s.date) < cutoff) continue;
      for (const ex of s.exercises || []) {
        const bp = (ex.bodyPart || getExerciseByName(ex.name)?.bodyPart || '').toLowerCase();
        const slugs = BP_MAP[bp];
        if (slugs) {
          const n = (ex.sets || []).filter(set => set.completed).length;
          slugs.forEach(slug => { counts[slug] = (counts[slug] || 0) + n; });
        }
      }
    }
    const result = {};
    for (const [k, v] of Object.entries(counts)) result[k] = Math.min(v / 20, 1);
    return result;
  }, [sessions]);

  return (
    <div onClick={onTap} style={{ margin: '0 16px 16px', background: 'var(--bg2)', borderRadius: 14, border: '1px solid var(--border)', overflow: 'hidden', cursor: 'pointer' }}>
      <div style={{ padding: '14px 16px 10px' }}>
        <span style={{ fontSize: 15, fontWeight: 700, color: 'var(--text)' }}>Last 7 days</span>
      </div>

      {/* 7-day strip */}
      <div style={{ display: 'flex', gap: 5, padding: '0 12px 14px' }}>
        {days.map((d, i) => {
          const key = d.toLocaleDateString('en-CA');
          const hasWorkout = sessionDateKeys.has(key);
          const isToday = i === 6;
          return (
            <div key={i} style={{
              flex: 1,
              display: 'flex', flexDirection: 'column', alignItems: 'center',
              padding: '7px 2px 5px',
              background: isToday ? 'var(--bg3)' : 'var(--bg)',
              borderRadius: 8,
              border: `1px solid ${isToday ? 'var(--accent)' : 'var(--border)'}`,
              gap: 2,
            }}>
              <span style={{ fontSize: 10, fontWeight: 600, color: isToday ? 'var(--accent)' : 'var(--text3)', letterSpacing: '0.03em' }}>
                {DAY_ABBR[d.getDay()]}
              </span>
              <span style={{ fontSize: 13, fontWeight: isToday ? 700 : 400, color: isToday ? 'var(--text)' : 'var(--text2)' }}>
                {d.getDate()}
              </span>
              <div style={{ width: 5, height: 5, borderRadius: '50%', background: hasWorkout ? 'var(--accent)' : 'transparent' }} />
            </div>
          );
        })}
      </div>

      {/* Front + back 3D body diagrams */}
      <div style={{ padding: '0 12px 16px' }}>
        <MuscleDiagram intensities={muscleIntensities} />
      </div>
    </div>
  );
}

// ── SessionCard ────────────────────────────────────────────────────────────────
function SessionCard({ session, onDelete, onCopy }) {
  const [expanded, setExpanded] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState(false);
  const longPressTimer = useRef(null);
  const menuRef = useRef(null);

  const volume = calcVolume(session.exercises || []);
  const sets   = calcSets(session.exercises || []);

  useEffect(() => {
    if (!menuOpen) return;
    const handler = (e) => {
      if (menuRef.current && !menuRef.current.contains(e.target)) {
        setMenuOpen(false);
        setConfirmDelete(false);
      }
    };
    document.addEventListener('mousedown', handler);
    document.addEventListener('touchstart', handler);
    return () => {
      document.removeEventListener('mousedown', handler);
      document.removeEventListener('touchstart', handler);
    };
  }, [menuOpen]);

  const handleLongPressStart = () => { longPressTimer.current = setTimeout(() => setMenuOpen(true), 500); };
  const handleLongPressEnd   = () => { if (longPressTimer.current) clearTimeout(longPressTimer.current); };

  return (
    <div
      style={{ background: 'var(--bg2)', borderRadius: 14, border: '1px solid var(--border)', marginBottom: 10, overflow: 'hidden', position: 'relative' }}
      onMouseDown={handleLongPressStart} onMouseUp={handleLongPressEnd} onMouseLeave={handleLongPressEnd}
      onTouchStart={handleLongPressStart} onTouchEnd={handleLongPressEnd}
    >
      <div style={{ padding: '14px 14px 10px', cursor: 'pointer' }} onClick={() => setExpanded(e => !e)}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{ fontWeight: 700, fontSize: 15, color: 'var(--text)', marginBottom: 2 }}>{session.title || 'Workout'}</div>
            <div style={{ fontSize: 12, color: 'var(--text3)' }}>{fmtTimeOfDay(session.date)}</div>
          </div>
          <button
            onClick={(e) => { e.stopPropagation(); setMenuOpen(o => !o); setConfirmDelete(false); }}
            style={{ background: 'none', border: 'none', color: 'var(--text3)', cursor: 'pointer', padding: '0 0 0 8px', display: 'flex', alignItems: 'center' }}
          >
            <MoreHorizontal size={18} />
          </button>
        </div>

        <div style={{ display: 'flex', gap: 18, marginTop: 10 }}>
          {[
            { label: 'Duration', value: fmtDuration(session.duration) },
            { label: 'Volume',   value: fmtVolLocal(volume) },
            { label: 'Sets',     value: String(sets) },
          ].map(({ label, value }) => (
            <div key={label}>
              <div style={{ fontSize: 11, color: 'var(--text3)', fontWeight: 600, marginBottom: 2 }}>{label}</div>
              <div style={{ fontSize: 14, fontWeight: 700, color: 'var(--text)' }}>{value}</div>
            </div>
          ))}
        </div>

        <div style={{ display: 'flex', justifyContent: 'center', marginTop: 6 }}>
          {expanded ? <ChevronUp size={16} color="var(--text3)" /> : <ChevronDown size={16} color="var(--text3)" />}
        </div>
      </div>

      {expanded && (
        <div style={{ padding: '0 14px 14px', borderTop: '1px solid var(--border)' }}>
          {(session.exercises || []).map((ex, i) => {
            const done = (ex.sets || []).filter(s => s.completed);
            if (!done.length) return null;
            return (
              <div key={i} style={{ marginTop: 10 }}>
                <div style={{ fontWeight: 600, fontSize: 13, color: 'var(--text)', marginBottom: 4 }}>{ex.name}</div>
                {done.map((set, j) => (
                  <div key={j} style={{ fontSize: 13, color: 'var(--text2)', paddingLeft: 8, marginBottom: 2, display: 'flex', gap: 10 }}>
                    <span style={{ color: 'var(--text3)', minWidth: 18 }}>{j + 1}</span>
                    {set.time > 0 && !set.reps
                      ? <span>{set.time}s</span>
                      : <span>{set.reps} reps{+set.weight > 0 ? ` @ ${set.weight}kg` : ''}</span>
                    }
                  </div>
                ))}
              </div>
            );
          })}
        </div>
      )}

      {menuOpen && (
        <div ref={menuRef} style={{ position: 'absolute', top: 36, right: 10, zIndex: 50, background: 'var(--bg3)', border: '1px solid var(--border)', borderRadius: 10, overflow: 'hidden', minWidth: 160, boxShadow: '0 6px 24px rgba(0,0,0,0.45)' }}>
          <button onClick={(e) => { e.stopPropagation(); onCopy(session); setMenuOpen(false); }} style={menuItemStyle}>
            Copy Workout
          </button>
          {!confirmDelete ? (
            <button onClick={(e) => { e.stopPropagation(); setConfirmDelete(true); }} style={{ ...menuItemStyle, color: '#EF4444' }}>
              Delete
            </button>
          ) : (
            <button onClick={(e) => { e.stopPropagation(); onDelete(session.id); setMenuOpen(false); }} style={{ ...menuItemStyle, color: '#EF4444', fontWeight: 700 }}>
              Confirm Delete
            </button>
          )}
        </div>
      )}
    </div>
  );
}

const menuItemStyle = {
  display: 'block', width: '100%', textAlign: 'left',
  padding: '12px 16px', background: 'none', border: 'none',
  color: 'var(--text)', fontSize: 14, cursor: 'pointer',
  borderBottom: '1px solid var(--border)',
};

// ── DayDetail overlay ─────────────────────────────────────────────────────────
function DayDetail({ date, sessions, onClose }) {
  return (
    <div style={{ position: 'fixed', inset: 0, zIndex: 400, background: 'var(--bg)', display: 'flex', flexDirection: 'column', animation: 'slideUp 0.22s ease-out' }}>
      <style>{`@keyframes slideUp { from { transform: translateY(32px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }`}</style>
      <div style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '16px 16px 12px', borderBottom: '1px solid var(--border)', flexShrink: 0 }}>
        <button onClick={onClose} style={{ background: 'none', border: 'none', color: 'var(--text)', cursor: 'pointer', display: 'flex', alignItems: 'center' }}>
          <ArrowLeft size={20} />
        </button>
        <span style={{ fontWeight: 700, fontSize: 17 }}>{fmtShortDate(date)}</span>
      </div>
      <div style={{ flex: 1, overflowY: 'auto', padding: '16px' }}>
        {sessions.map((session) => {
          const sets = calcSets(session.exercises || []);
          return (
            <div key={session.id} style={{ background: 'var(--bg2)', borderRadius: 12, border: '1px solid var(--border)', padding: '14px', marginBottom: 12 }}>
              <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 2 }}>{session.title || 'Workout'}</div>
              <div style={{ fontSize: 12, color: 'var(--text3)', marginBottom: 10 }}>{fmtDuration(session.duration)} · {sets} sets</div>
              {(session.exercises || []).map((ex, i) => {
                const done = (ex.sets || []).filter(s => s.completed);
                if (!done.length) return null;
                return (
                  <div key={i} style={{ marginBottom: 8 }}>
                    <div style={{ fontWeight: 600, fontSize: 13, marginBottom: 3 }}>{ex.name}</div>
                    {done.map((set, j) => (
                      <div key={j} style={{ fontSize: 13, color: 'var(--text2)', paddingLeft: 8, marginBottom: 2, display: 'flex', gap: 10 }}>
                        <span style={{ color: 'var(--text3)', minWidth: 18 }}>{j + 1}</span>
                        {set.time > 0 && !set.reps ? <span>{set.time}s</span> : <span>{set.reps} reps{+set.weight > 0 ? ` @ ${set.weight}kg` : ''}</span>}
                      </div>
                    ))}
                  </div>
                );
              })}
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ── Calendar ──────────────────────────────────────────────────────────────────
const DAY_LABELS  = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
const MONTH_NAMES = ['January','February','March','April','May','June','July','August','September','October','November','December'];

function Calendar({ sessions, onDayClick }) {
  const [month, setMonth] = useState(() => {
    const d = new Date(); d.setDate(1); d.setHours(0, 0, 0, 0); return d;
  });

  const today = new Date(); today.setHours(0, 0, 0, 0);

  const sessionDates = new Map();
  for (const s of sessions) {
    const key = new Date(s.date).toLocaleDateString('en-CA');
    if (!sessionDates.has(key)) sessionDates.set(key, []);
    sessionDates.get(key).push(s);
  }

  const year = month.getFullYear();
  const monthIdx = month.getMonth();
  const firstDow = new Date(year, monthIdx, 1).getDay();
  const daysInMonth = new Date(year, monthIdx + 1, 0).getDate();

  const cells = [];
  for (let i = 0; i < firstDow; i++) cells.push(null);
  for (let d = 1; d <= daysInMonth; d++) cells.push(d);

  const prevMonth = () => setMonth(m => { const n = new Date(m); n.setMonth(n.getMonth() - 1); return n; });
  const nextMonth = () => setMonth(m => { const n = new Date(m); n.setMonth(n.getMonth() + 1); return n; });

  return (
    <div style={{ padding: '16px 0 0' }}>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 14, padding: '0 4px' }}>
        <button onClick={prevMonth} style={{ background: 'none', border: 'none', color: 'var(--text2)', cursor: 'pointer', padding: '4px 8px', borderRadius: 8, display: 'flex', alignItems: 'center' }}>
          <ChevronLeft size={20} />
        </button>
        <span style={{ fontWeight: 600, fontSize: 15, color: 'var(--text)' }}>{MONTH_NAMES[monthIdx]} {year}</span>
        <button onClick={nextMonth} style={{ background: 'none', border: 'none', color: 'var(--text2)', cursor: 'pointer', padding: '4px 8px', borderRadius: 8, display: 'flex', alignItems: 'center' }}>
          <ChevronRight size={20} />
        </button>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', marginBottom: 6 }}>
        {DAY_LABELS.map(d => (
          <div key={d} style={{ textAlign: 'center', fontSize: 11, color: 'var(--text3)', fontWeight: 600, padding: '2px 0' }}>{d}</div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: 3 }}>
        {cells.map((day, idx) => {
          if (!day) return <div key={`empty-${idx}`} />;
          const cellDate = new Date(year, monthIdx, day);
          cellDate.setHours(0, 0, 0, 0);
          const dateKey = cellDate.toLocaleDateString('en-CA');
          const hasSessions = sessionDates.has(dateKey);
          const isToday = cellDate.getTime() === today.getTime();

          return (
            <div
              key={day}
              onClick={() => hasSessions && onDayClick(cellDate.toISOString(), sessionDates.get(dateKey))}
              style={{
                display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
                padding: '10px 0 6px',
                borderRadius: 8,
                cursor: hasSessions ? 'pointer' : 'default',
                background: isToday ? 'var(--bg3)' : 'transparent',
                outline: isToday ? '1px solid var(--text3)' : 'none',
                outlineOffset: '-1px',
                gap: 3,
              }}
            >
              <span style={{ fontSize: 13, fontWeight: isToday ? 700 : 400, color: isToday ? 'var(--text)' : 'var(--text2)' }}>
                {day}
              </span>
              <div style={{ width: 5, height: 5, borderRadius: '50%', background: hasSessions ? 'var(--accent)' : 'transparent' }} />
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ── Toast ─────────────────────────────────────────────────────────────────────
function Toast({ message, onDone }) {
  useEffect(() => { const t = setTimeout(onDone, 2400); return () => clearTimeout(t); }, [onDone]);
  return (
    <div style={{ position: 'fixed', bottom: 80, left: '50%', transform: 'translateX(-50%)', background: 'var(--bg3)', color: 'var(--text)', padding: '10px 20px', borderRadius: 10, fontSize: 14, fontWeight: 500, boxShadow: '0 4px 20px rgba(0,0,0,0.5)', zIndex: 500, border: '1px solid var(--border)', whiteSpace: 'nowrap' }}>
      {message}
    </div>
  );
}

// ── DashboardTile ─────────────────────────────────────────────────────────────
function DashboardTile({ icon: Icon, label, onTap }) {
  return (
    <button onClick={onTap} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: 8, padding: '18px 8px', background: 'var(--bg2)', border: '1px solid var(--border)', borderRadius: 14, cursor: 'pointer', color: 'var(--text)', transition: 'background 0.15s', width: '100%' }}>
      <Icon size={24} color="var(--accent)" />
      <span style={{ fontSize: 13, fontWeight: 600, color: 'var(--text2)' }}>{label}</span>
    </button>
  );
}

// ── CalendarView ──────────────────────────────────────────────────────────────
function CalendarView({ sessions, onBack }) {
  const [expandedDay, setExpandedDay] = useState(null);
  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column', background: 'var(--bg)' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '56px 16px 14px', borderBottom: '1px solid var(--border)', flexShrink: 0 }}>
        <button onClick={onBack} style={{ background: 'none', border: 'none', color: 'var(--text)', cursor: 'pointer', display: 'flex', alignItems: 'center', padding: '0 4px 0 0' }}>
          <ArrowLeft size={22} />
        </button>
        <h1 style={{ fontSize: 28, fontWeight: 800, color: 'var(--text)' }}>Calendar</h1>
      </div>
      <div style={{ flex: 1, overflowY: 'auto', padding: '0 16px 32px' }}>
        <Calendar sessions={sessions} onDayClick={(dateIso, daySessions) => setExpandedDay({ date: dateIso, sessions: daySessions })} />
      </div>
      {expandedDay && <DayDetail date={expandedDay.date} sessions={expandedDay.sessions} onClose={() => setExpandedDay(null)} />}
    </div>
  );
}

// ── HistoryTab ────────────────────────────────────────────────────────────────
export default function HistoryTab({ active }) {
  const [sessions, setSessions] = useState([]);
  const [view, setView] = useState('main');
  const [toast, setToast] = useState(null);

  const loadSessions = useCallback(async () => {
    const all = await getAllSessions();
    all.sort((a, b) => new Date(b.date) - new Date(a.date));
    setSessions(all);
  }, []);

  useEffect(() => { if (active) loadSessions(); }, [active, loadSessions]);

  const handleDelete = useCallback(async (id) => {
    await deleteSession(id);
    setSessions(prev => prev.filter(s => s.id !== id));
  }, []);

  const handleCopy = useCallback(async (session) => {
    const routine = {
      id: `routine-copy-${Date.now()}`,
      title: session.title || 'Copied Workout',
      createdAt: new Date().toISOString(),
      exercises: (session.exercises || []).map(ex => ({
        name: ex.name,
        sets: (ex.sets || []).filter(s => s.completed).map(s => ({ ...s, completed: false })),
      })),
    };
    await saveRoutine(routine);
    setToast('Copied to My Routines');
  }, []);

  const groups = useMemo(() => {
    const result = [];
    const seen = new Map();
    for (const s of sessions) {
      const label = fmtDate(s.date);
      if (!seen.has(label)) { seen.set(label, []); result.push({ label, items: seen.get(label) }); }
      seen.get(label).push(s);
    }
    return result;
  }, [sessions]);

  return (
    <>
      {/* ── Main view ── */}
      <div style={{ display: view === 'main' ? 'flex' : 'none', flexDirection: 'column', height: '100vh', background: 'var(--bg)' }}>
        <div style={{ padding: '56px 16px 16px', borderBottom: '1px solid var(--border)', flexShrink: 0 }}>
          <h1 style={{ fontSize: 28, fontWeight: 800, color: 'var(--text)' }}>History</h1>
        </div>

        <div style={{ flex: 1, overflowY: 'auto', padding: '0 0 80px' }}>
          <div style={{ paddingTop: 16 }}>
            <BodyGraph sessions={sessions} onTap={() => setView('body')} />
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 10, padding: '0 16px', marginBottom: 24 }}>
            <DashboardTile icon={TrendingUp}   label="Statistics" onTap={() => setView('statistics')} />
            <DashboardTile icon={Dumbbell}     label="Exercises"  onTap={() => setView('exercises')} />
            <DashboardTile icon={CalendarIcon} label="Calendar"   onTap={() => setView('calendar')} />
          </div>

          <div style={{ padding: '0 16px' }}>
            <h2 style={{ fontSize: 18, fontWeight: 700, marginBottom: 14 }}>Recent Workouts</h2>
            {sessions.length === 0 ? (
              <div style={{ color: 'var(--text3)', fontSize: 14, textAlign: 'center', padding: '32px 0' }}>
                No workouts yet. Complete a session to see it here.
              </div>
            ) : (
              groups.map(({ label, items }) => (
                <div key={label}>
                  <div style={{ fontSize: 12, fontWeight: 700, color: 'var(--text3)', textTransform: 'uppercase', letterSpacing: '0.8px', marginBottom: 8, marginTop: 16 }}>
                    {label}
                  </div>
                  {items.map(session => (
                    <SessionCard key={session.id} session={session} onDelete={handleDelete} onCopy={handleCopy} />
                  ))}
                </div>
              ))
            )}
          </div>
        </div>
      </div>

      {/* ── Sub-view overlays ── */}
      {view === 'statistics' && (
        <div style={{ position: 'fixed', inset: 0, zIndex: 150, background: 'var(--bg)' }}>
          <ProgressTab active={true} onBack={() => setView('main')} />
        </div>
      )}
      {view === 'exercises' && (
        <div style={{ position: 'fixed', inset: 0, zIndex: 150, background: '#020210' }}>
          <ExercisesTab onBack={() => setView('main')} />
        </div>
      )}
      {view === 'calendar' && (
        <div style={{ position: 'fixed', inset: 0, zIndex: 150, background: 'var(--bg)' }}>
          <CalendarView sessions={sessions} onBack={() => setView('main')} />
        </div>
      )}

      {view === 'body' && <BodyDistributionView sessions={sessions} onClose={() => setView('main')} />}

      {toast && <Toast message={toast} onDone={() => setToast(null)} />}
    </>
  );
}
