import { useState, useEffect, useMemo, useCallback } from 'react';
import { Settings, ChevronRight, Search, X, ArrowLeft } from 'lucide-react';
import { getAllSessions } from '../db';
import { fmtDuration } from '../utils/format';
import { calcVolume, calcSets } from '../utils/stats';
import { useApp } from '../contexts/AppContext';
import { getExerciseByName } from '../utils/exercises';
import ExerciseDetail from './ExerciseDetail';

// ── Helpers ────────────────────────────────────────────────────────────────────

function fmtVol(kg) {
  if (!kg || kg === 0) return '0 kg';
  if (kg >= 1000) return `${(kg / 1000).toFixed(1)}k kg`;
  return `${Math.round(kg)} kg`;
}

const PERIODS = [
  { id: '1m',  label: '1M' },
  { id: '3m',  label: '3M' },
  { id: '1y',  label: '1Y' },
  { id: 'all', label: 'All' },
];

function filterByPeriod(sessions, period) {
  if (period === 'all') return sessions;
  const now = Date.now();
  const ms = period === '1m' ? 30 : period === '3m' ? 90 : 365;
  const cutoff = now - ms * 24 * 60 * 60 * 1000;
  return sessions.filter(s => new Date(s.date).getTime() >= cutoff);
}

const DAY_SHORTS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

// ── Settings Modal ─────────────────────────────────────────────────────────────
function SettingsModal({ onClose }) {
  const { settings, updateSetting } = useApp();

  return (
    <div style={{
      position: 'fixed', inset: 0, zIndex: 500,
      display: 'flex', flexDirection: 'column', justifyContent: 'flex-end',
    }}>
      {/* Backdrop */}
      <div
        style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.6)' }}
        onClick={onClose}
      />
      {/* Sheet */}
      <div style={{
        position: 'relative',
        background: 'var(--bg2)',
        borderRadius: '18px 18px 0 0',
        padding: '20px 20px 40px',
        border: '1px solid var(--border)',
        borderBottom: 'none',
        animation: 'slideUp 0.22s ease-out',
      }}>
        <style>{`
          @keyframes slideUp {
            from { transform: translateY(24px); opacity: 0; }
            to   { transform: translateY(0);    opacity: 1; }
          }
        `}</style>

        {/* Handle */}
        <div style={{
          width: 36, height: 4, background: 'var(--border)',
          borderRadius: 2, margin: '0 auto 20px',
        }} />

        <h2 style={{ fontSize: 20, fontWeight: 800, marginBottom: 24 }}>Settings</h2>

        {/* Units */}
        <SettingsRow label="Units">
          <div style={{ display: 'flex', background: 'var(--bg3)', borderRadius: 8, padding: 2, gap: 2 }}>
            {['kg', 'lbs'].map(u => (
              <button
                key={u}
                onClick={() => updateSetting('units', u)}
                style={{
                  padding: '5px 18px',
                  borderRadius: 7,
                  border: 'none',
                  cursor: 'pointer',
                  fontWeight: 600,
                  fontSize: 14,
                  background: settings.units === u ? 'var(--accent)' : 'transparent',
                  color: settings.units === u ? '#fff' : 'var(--text2)',
                  transition: 'background 0.15s, color 0.15s',
                }}
              >
                {u}
              </button>
            ))}
          </div>
        </SettingsRow>

        {/* Default Rest Timer */}
        <SettingsRow label="Default Rest Timer">
          <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <input
              type="number"
              value={settings.defaultRest ?? 90}
              onChange={e => updateSetting('defaultRest', Number(e.target.value))}
              style={{
                width: 70, padding: '6px 10px',
                background: 'var(--bg3)', border: '1px solid var(--border)',
                borderRadius: 8, color: 'var(--text)', fontSize: 14,
                textAlign: 'center',
              }}
              min={0}
            />
            <span style={{ fontSize: 14, color: 'var(--text2)' }}>sec</span>
          </div>
        </SettingsRow>

        {/* Keep Awake */}
        <SettingsRow label="Keep Awake During Workout">
          <Toggle
            on={!!settings.keepAwake}
            onChange={v => updateSetting('keepAwake', v)}
          />
        </SettingsRow>

        {/* RPE Tracking */}
        <SettingsRow label="RPE Tracking">
          <Toggle
            on={!!settings.rpeEnabled}
            onChange={v => updateSetting('rpeEnabled', v)}
          />
        </SettingsRow>

        {/* Close */}
        <button
          onClick={onClose}
          style={{
            marginTop: 24,
            width: '100%',
            padding: '13px',
            borderRadius: 12,
            background: 'var(--bg3)',
            border: '1px solid var(--border)',
            color: 'var(--text)',
            fontSize: 15,
            fontWeight: 600,
            cursor: 'pointer',
          }}
        >
          Close
        </button>
      </div>
    </div>
  );
}

function SettingsRow({ label, children }) {
  return (
    <div style={{
      display: 'flex', alignItems: 'center', justifyContent: 'space-between',
      padding: '14px 0',
      borderBottom: '1px solid var(--border)',
    }}>
      <span style={{ fontSize: 15, color: 'var(--text)' }}>{label}</span>
      {children}
    </div>
  );
}

function Toggle({ on, onChange }) {
  return (
    <button
      role="switch"
      aria-checked={on}
      onClick={() => onChange(!on)}
      style={{
        width: 46, height: 26,
        borderRadius: 13,
        border: 'none',
        background: on ? 'var(--accent)' : 'var(--bg3)',
        cursor: 'pointer',
        position: 'relative',
        transition: 'background 0.2s',
        flexShrink: 0,
      }}
    >
      <span style={{
        position: 'absolute',
        top: 3, left: on ? 23 : 3,
        width: 20, height: 20,
        borderRadius: '50%',
        background: '#fff',
        transition: 'left 0.2s',
        boxShadow: '0 1px 4px rgba(0,0,0,0.35)',
      }} />
    </button>
  );
}

// ── Weekly Activity Bar Chart ──────────────────────────────────────────────────
function WeeklyActivity({ sessions }) {
  const days = useMemo(() => {
    const result = [];
    const now = new Date();
    for (let i = 6; i >= 0; i--) {
      const d = new Date(now);
      d.setDate(d.getDate() - i);
      d.setHours(0, 0, 0, 0);
      const key = d.toLocaleDateString('en-CA');
      const daySessions = sessions.filter(s => new Date(s.date).toLocaleDateString('en-CA') === key);
      const totalDuration = daySessions.reduce((a, s) => a + (s.duration || 0), 0);
      result.push({
        key,
        label: DAY_SHORTS[d.getDay()],
        isToday: i === 0,
        duration: totalDuration,
        minutes: Math.round(totalDuration / 60),
      });
    }
    return result;
  }, [sessions]);

  const maxDuration = Math.max(...days.map(d => d.duration), 1);
  const MAX_HEIGHT = 80;

  return (
    <div style={{
      display: 'flex', alignItems: 'flex-end', gap: 6,
      height: MAX_HEIGHT + 44,
      paddingBottom: 0,
    }}>
      {days.map(day => {
        const pct = day.duration / maxDuration;
        const barH = day.duration > 0 ? Math.max(pct * MAX_HEIGHT, 6) : 0;

        let barBg = 'var(--bg3)';
        if (day.isToday) barBg = 'var(--accent)';
        else if (day.duration > 0) barBg = 'rgba(var(--accent-rgb, 99,102,241),0.6)';

        return (
          <div key={day.key} style={{
            flex: 1, display: 'flex', flexDirection: 'column',
            alignItems: 'center', gap: 4, justifyContent: 'flex-end',
          }}>
            {/* Bar container — fixed height so bars grow upward */}
            <div style={{ height: MAX_HEIGHT, display: 'flex', alignItems: 'flex-end', width: '100%' }}>
              <div style={{
                width: '100%',
                height: barH,
                background: barBg,
                borderRadius: '4px 4px 2px 2px',
                transition: 'height 0.3s ease',
              }} />
            </div>
            {/* Day label */}
            <span style={{ fontSize: 11, color: day.isToday ? 'var(--text)' : 'var(--text3)', fontWeight: day.isToday ? 700 : 400 }}>
              {day.label}
            </span>
            {/* Minutes label */}
            <span style={{ fontSize: 10, color: 'var(--text3)', minHeight: 14, lineHeight: '14px' }}>
              {day.minutes > 0 ? `${day.minutes}m` : ''}
            </span>
          </div>
        );
      })}
    </div>
  );
}

// ── Muscle Focus bars ──────────────────────────────────────────────────────────
function MuscleFocus({ sessions }) {
  const bodyPartCounts = useMemo(() => {
    const counts = {};
    for (const s of sessions) {
      for (const ex of (s.exercises || [])) {
        const done = (ex.sets || []).filter(s => s.completed).length;
        if (!done) continue;
        const bp = ex.bodyPart || 'Other';
        counts[bp] = (counts[bp] || 0) + done;
      }
    }
    return Object.entries(counts).sort((a, b) => b[1] - a[1]);
  }, [sessions]);

  if (!bodyPartCounts.length) {
    return <div style={{ color: 'var(--text3)', fontSize: 14, padding: '12px 0' }}>No data for this period.</div>;
  }

  const max = bodyPartCounts[0][1];

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
      {bodyPartCounts.map(([bp, count]) => (
        <div key={bp} style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <span style={{ fontSize: 13, color: 'var(--text2)', minWidth: 90, textTransform: 'capitalize' }}>
            {bp}
          </span>
          <div style={{ flex: 1, height: 8, background: 'var(--bg3)', borderRadius: 4, overflow: 'hidden' }}>
            <div style={{
              height: '100%',
              width: `${(count / max) * 100}%`,
              background: 'var(--accent)',
              borderRadius: 4,
              transition: 'width 0.4s ease',
            }} />
          </div>
          <span style={{ fontSize: 12, color: 'var(--text3)', minWidth: 36, textAlign: 'right' }}>
            {count} sets
          </span>
        </div>
      ))}
    </div>
  );
}

// ── Stat Card ──────────────────────────────────────────────────────────────────
function StatCard({ label, value, sub }) {
  return (
    <div style={{
      background: 'var(--bg2)',
      borderRadius: 12,
      border: '1px solid var(--border)',
      padding: '14px 16px',
      display: 'flex', flexDirection: 'column', gap: 4,
    }}>
      <span style={{ fontSize: 12, color: 'var(--text3)', textTransform: 'uppercase', letterSpacing: '0.5px', fontWeight: 600 }}>{label}</span>
      <span style={{ fontSize: 22, fontWeight: 800, color: 'var(--text)', lineHeight: 1.1 }}>{value}</span>
      {sub && <span style={{ fontSize: 12, color: 'var(--text3)' }}>{sub}</span>}
    </div>
  );
}

// ── Section wrapper ────────────────────────────────────────────────────────────
function Section({ title, children }) {
  return (
    <div style={{ marginBottom: 24 }}>
      <h2 style={{ fontSize: 17, fontWeight: 700, marginBottom: 14, color: 'var(--text)' }}>{title}</h2>
      {children}
    </div>
  );
}

// ── ProgressTab ────────────────────────────────────────────────────────────────
export default function ProgressTab({ active, onBack }) {
  const [sessions, setSessions] = useState([]);
  const [period, setPeriod] = useState('all');
  const [selectedExercise, setSelectedExercise] = useState(null);
  const [showSettings, setShowSettings] = useState(false);
  const [query, setQuery] = useState('');

  useEffect(() => {
    if (!active) return;
    getAllSessions().then(all => {
      all.sort((a, b) => new Date(b.date) - new Date(a.date));
      setSessions(all);
    });
  }, [active]);

  const filtered = useMemo(() => filterByPeriod(sessions, period), [sessions, period]);

  // Overview stats
  const totalVolume = useMemo(() => filtered.reduce((a, s) => a + calcVolume(s.exercises || []), 0), [filtered]);
  const totalSets = useMemo(() => filtered.reduce((a, s) => a + calcSets(s.exercises || []), 0), [filtered]);
  const totalDuration = useMemo(() => filtered.reduce((a, s) => a + (s.duration || 0), 0), [filtered]);

  // All unique exercise names from all sessions (not filtered — for discovery lists)
  const allExerciseNames = useMemo(() => {
    const set = new Set();
    for (const s of sessions) {
      for (const ex of (s.exercises || [])) {
        if (ex.name) set.add(ex.name);
      }
    }
    return [...set].sort((a, b) => a.localeCompare(b));
  }, [sessions]);

  // Recent exercises: 8 most recently performed, from newest sessions
  const recentExerciseNames = useMemo(() => {
    const seen = new Set();
    const result = [];
    for (const s of sessions) { // already sorted newest first
      for (const ex of (s.exercises || [])) {
        if (ex.name && !seen.has(ex.name)) {
          seen.add(ex.name);
          result.push(ex.name);
          if (result.length >= 8) return result;
        }
      }
    }
    return result;
  }, [sessions]);

  // Top exercises: count completed sets per exercise name in filtered sessions
  const topExercises = useMemo(() => {
    const counts = {};
    for (const s of filtered) {
      for (const ex of (s.exercises || [])) {
        const done = (ex.sets || []).filter(s => s.completed).length;
        if (!done || !ex.name) continue;
        counts[ex.name] = (counts[ex.name] || 0) + done;
      }
    }
    return Object.entries(counts)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 8);
  }, [filtered]);

  const resolveExercise = useCallback((name) => {
    const found = getExerciseByName(name);
    return found || { name, bodyPart: '', equipment: '', trackingType: 'reps' };
  }, []);

  const handleSelectExercise = useCallback((name) => {
    setSelectedExercise(resolveExercise(name));
  }, [resolveExercise]);

  // Filtered search list
  const searchResults = useMemo(() => {
    if (!query.trim()) return allExerciseNames;
    const q = query.toLowerCase();
    return allExerciseNames.filter(n => n.toLowerCase().includes(q));
  }, [allExerciseNames, query]);

  return (
    <>
      <div style={{ height: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--bg)' }}>
        {/* Header */}
        <div style={{
          padding: '56px 16px 14px',
          borderBottom: '1px solid var(--border)',
          flexShrink: 0,
          display: 'flex', alignItems: 'flex-end', justifyContent: 'space-between',
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
            {onBack && (
              <button
                onClick={onBack}
                style={{ background: 'none', border: 'none', color: 'var(--text)', cursor: 'pointer', display: 'flex', alignItems: 'center', padding: '0 8px 2px 0' }}
              >
                <ArrowLeft size={22} />
              </button>
            )}
            <h1 style={{ fontSize: 28, fontWeight: 800, color: 'var(--text)' }}>{onBack ? 'Statistics' : 'Progress'}</h1>
          </div>
          <button
            onClick={() => setShowSettings(true)}
            style={{
              background: 'none', border: 'none',
              color: 'var(--text2)', cursor: 'pointer',
              padding: '6px', borderRadius: 8,
              display: 'flex', alignItems: 'center',
            }}
            aria-label="Settings"
          >
            <Settings size={22} />
          </button>
        </div>

        {/* Scrollable body */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '16px 16px 80px' }}>

          {/* Period selector */}
          <div style={{
            display: 'flex',
            background: 'var(--bg2)',
            border: '1px solid var(--border)',
            borderRadius: 10,
            padding: 3,
            gap: 2,
            marginBottom: 24,
          }}>
            {PERIODS.map(p => (
              <button
                key={p.id}
                onClick={() => setPeriod(p.id)}
                style={{
                  flex: 1, padding: '7px 0',
                  borderRadius: 8,
                  border: 'none',
                  cursor: 'pointer',
                  fontWeight: 600,
                  fontSize: 14,
                  background: period === p.id ? 'var(--accent)' : 'transparent',
                  color: period === p.id ? '#fff' : 'var(--text2)',
                  transition: 'background 0.15s, color 0.15s',
                }}
              >
                {p.label}
              </button>
            ))}
          </div>

          {/* Overview stats 2×2 */}
          <Section title="Overview">
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
              <StatCard label="Workouts" value={filtered.length} />
              <StatCard label="Total Volume" value={fmtVol(totalVolume)} />
              <StatCard label="Total Sets" value={totalSets} />
              <StatCard label="Time Trained" value={fmtDuration(totalDuration)} />
            </div>
          </Section>

          {/* Weekly Activity */}
          <Section title="Weekly Activity">
            <div style={{
              background: 'var(--bg2)',
              borderRadius: 14,
              border: '1px solid var(--border)',
              padding: '16px',
            }}>
              <WeeklyActivity sessions={filtered} />
            </div>
          </Section>

          {/* Muscle Focus */}
          <Section title="Muscle Focus">
            <div style={{
              background: 'var(--bg2)',
              borderRadius: 14,
              border: '1px solid var(--border)',
              padding: '16px',
            }}>
              <MuscleFocus sessions={filtered} />
            </div>
          </Section>

          {/* Top Exercises */}
          <Section title="Top Exercises">
            <div style={{
              background: 'var(--bg2)',
              borderRadius: 14,
              border: '1px solid var(--border)',
              overflow: 'hidden',
            }}>
              {topExercises.length === 0 ? (
                <div style={{ padding: '16px', color: 'var(--text3)', fontSize: 14 }}>
                  No exercises logged in this period.
                </div>
              ) : (
                topExercises.map(([name, count], idx) => (
                  <button
                    key={name}
                    onClick={() => handleSelectExercise(name)}
                    style={{
                      display: 'flex', alignItems: 'center', gap: 12,
                      width: '100%', padding: '13px 14px',
                      background: 'none', border: 'none',
                      borderBottom: idx < topExercises.length - 1 ? '1px solid var(--border)' : 'none',
                      cursor: 'pointer',
                      textAlign: 'left',
                      color: 'var(--text)',
                    }}
                  >
                    <span style={{
                      width: 24, height: 24, borderRadius: 6,
                      background: 'var(--bg3)',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      fontSize: 11, fontWeight: 800, color: 'var(--text3)',
                      flexShrink: 0,
                    }}>
                      {idx + 1}
                    </span>
                    <span style={{ flex: 1, fontSize: 15, fontWeight: 500 }}>{name}</span>
                    <span style={{ fontSize: 12, color: 'var(--text3)', marginRight: 4 }}>{count} sets</span>
                    <ChevronRight size={16} color="var(--text3)" />
                  </button>
                ))
              )}
            </div>
          </Section>

          {/* Exercise Progress */}
          <Section title="Exercise Progress">
            {/* Search bar */}
            <div style={{
              position: 'relative', marginBottom: 14,
            }}>
              <Search size={16} style={{
                position: 'absolute', left: 12, top: '50%',
                transform: 'translateY(-50%)', color: 'var(--text3)',
                pointerEvents: 'none',
              }} />
              <input
                type="text"
                placeholder="Search exercises..."
                value={query}
                onChange={e => setQuery(e.target.value)}
                style={{
                  width: '100%',
                  padding: '11px 36px 11px 38px',
                  background: 'var(--bg2)',
                  border: '1px solid var(--border)',
                  borderRadius: 10,
                  color: 'var(--text)',
                  fontSize: 15,
                  outline: 'none',
                }}
              />
              {query && (
                <button
                  onClick={() => setQuery('')}
                  style={{
                    position: 'absolute', right: 10, top: '50%',
                    transform: 'translateY(-50%)',
                    background: 'none', border: 'none',
                    color: 'var(--text3)', cursor: 'pointer',
                    display: 'flex', alignItems: 'center', padding: 4,
                  }}
                >
                  <X size={15} />
                </button>
              )}
            </div>

            {/* Recent chips — only shown when not searching */}
            {!query && recentExerciseNames.length > 0 && (
              <div style={{ marginBottom: 14 }}>
                <div style={{ fontSize: 12, color: 'var(--text3)', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: 8 }}>
                  Recent
                </div>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                  {recentExerciseNames.map(name => (
                    <button
                      key={name}
                      onClick={() => handleSelectExercise(name)}
                      style={{
                        padding: '6px 14px',
                        borderRadius: 20,
                        border: '1px solid var(--border)',
                        background: 'var(--bg2)',
                        color: 'var(--text)',
                        fontSize: 13,
                        cursor: 'pointer',
                        whiteSpace: 'nowrap',
                      }}
                    >
                      {name}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {/* Full A-Z list */}
            <div style={{
              background: 'var(--bg2)',
              borderRadius: 14,
              border: '1px solid var(--border)',
              overflow: 'hidden',
            }}>
              {searchResults.length === 0 ? (
                <div style={{ padding: '16px', color: 'var(--text3)', fontSize: 14 }}>
                  {query ? 'No exercises match your search.' : 'No exercises logged yet.'}
                </div>
              ) : (
                searchResults.map((name, idx) => (
                  <button
                    key={name}
                    onClick={() => handleSelectExercise(name)}
                    style={{
                      display: 'flex', alignItems: 'center',
                      width: '100%', padding: '13px 14px',
                      background: 'none', border: 'none',
                      borderBottom: idx < searchResults.length - 1 ? '1px solid var(--border)' : 'none',
                      cursor: 'pointer',
                      textAlign: 'left',
                      color: 'var(--text)',
                    }}
                  >
                    <span style={{ flex: 1, fontSize: 15 }}>{name}</span>
                    <ChevronRight size={16} color="var(--text3)" />
                  </button>
                ))
              )}
            </div>
          </Section>

        </div>
      </div>

      {/* ExerciseDetail overlay */}
      {selectedExercise && (
        <ExerciseDetail
          exercise={selectedExercise}
          onBack={() => setSelectedExercise(null)}
        />
      )}

      {/* Settings modal */}
      {showSettings && (
        <SettingsModal onClose={() => setShowSettings(false)} />
      )}
    </>
  );
}
