import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Dumbbell, User, ArrowLeft } from 'lucide-react';
import { AppProvider } from './contexts/AppContext';
import { WorkoutProvider, useWorkout } from './contexts/WorkoutContext';
import WorkoutTab from './components/WorkoutTab';
import HistoryTab from './components/HistoryTab';
import LiveWorkout from './components/LiveWorkout';
import './index.css';

export default function GymApp() {
  return (
    <AppProvider>
      <WorkoutProvider>
        <GymAppInner />
      </WorkoutProvider>
    </AppProvider>
  );
}

// true on devices that have a real pointer (desktop/laptop)
const hasHover = window.matchMedia('(hover: hover)').matches;

function GymAppInner() {
  const navigate = useNavigate();
  const { session } = useWorkout();
  const [tab, setTab] = useState('workout');
  // On touch devices bar is always visible; on desktop show only near top
  const [barVisible, setBarVisible] = useState(!hasHover);

  useEffect(() => {
    if (!hasHover) return;
    const onMove = (e) => setBarVisible(e.clientY < 64);
    window.addEventListener('mousemove', onMove);
    return () => window.removeEventListener('mousemove', onMove);
  }, []);

  const TABS = [
    { id: 'workout', label: 'Workout', icon: Dumbbell },
    { id: 'history', label: 'History', icon: User },
  ];

  return (
    <div className="app">
      {/* Top bar — hidden during active session */}
      {!session && (
        <div className={`top-bar${barVisible ? ' top-bar--visible' : ''}`}>
          <button className="top-bar-back" onClick={() => navigate('/')}>
            <ArrowLeft size={14} />
            <span>Apps</span>
          </button>
        </div>
      )}

      {/* Tab content — use display:none trick to preserve state across tab switches */}
      <div style={{ display: tab === 'workout' ? 'contents' : 'none' }}><WorkoutTab active={tab === 'workout'} /></div>
      <div style={{ display: tab === 'history' ? 'contents' : 'none' }}><HistoryTab active={tab === 'history'} /></div>

      {/* Bottom nav — always visible */}
      <nav className="bottom-nav">
        {TABS.map(({ id, label, icon: Icon }) => (
          <button
            key={id}
            className={`nav-btn${tab === id ? ' active' : ''}`}
            onClick={() => setTab(id)}
          >
            <Icon size={22} />
            <span>{label}</span>
          </button>
        ))}
      </nav>

      {/* Live workout overlay — renders on top of everything when a session is active */}
      {session && <LiveWorkout onFinished={() => setTab('history')} />}
    </div>
  );
}
